import{c as e,Q as i,j as s,m as l}from"./chunks/framework.5k1Nei9d.js";const k=JSON.parse('{"title":"Recovery 刷入指南","description":"","frontmatter":{},"headers":[],"relativePath":"tutorials/android-recovery.md","filePath":"tutorials/android-recovery.md"}'),r={name:"tutorials/android-recovery.md"};function o(n,a,t,h,p,c){return i(),s("div",null,[...a[0]||(a[0]=[l(`<h1 id="recovery-刷入指南" tabindex="-1">Recovery 刷入指南 <a class="header-anchor" href="#recovery-刷入指南" aria-label="Permalink to &quot;Recovery 刷入指南&quot;">​</a></h1><h2 id="什么是-recovery" tabindex="-1">什么是 Recovery？ <a class="header-anchor" href="#什么是-recovery" aria-label="Permalink to &quot;什么是 Recovery？&quot;">​</a></h2><p>Recovery 是 Android 的恢复模式，第三方 Recovery（如 TWRP / OrangeFox）提供了比官方更强大的功能：</p><ul><li>刷入 ROM / Magisk</li><li>备份和还原系统</li><li>清除数据 / 格式化分区</li><li>文件管理</li></ul><h2 id="刷入-twrp" tabindex="-1">刷入 TWRP <a class="header-anchor" href="#刷入-twrp" aria-label="Permalink to &quot;刷入 TWRP&quot;">​</a></h2><ol><li>在 <a href="https://twrp.me/Devices/" target="_blank" rel="noreferrer">TWRP 官网</a> 下载对应机型的镜像文件</li><li>手机关机，进入 Fastboot 模式</li><li>连接电脑，刷入：</li></ol><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 临时启动（推荐先测试）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">fastboot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> boot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> twrp.img</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 永久刷入</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">fastboot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> flash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> recovery</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> twrp.img</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><div class="warning custom-block"><p class="custom-block-title">注意</p><p>部分机型（如小米）的 Recovery 和 Boot 分区合并，需要刷入 <code>boot.img</code> 方式。 务必确认自己机型的 Recovery 分区情况！</p></div><h2 id="刷入-orangefox" tabindex="-1">刷入 OrangeFox <a class="header-anchor" href="#刷入-orangefox" aria-label="Permalink to &quot;刷入 OrangeFox&quot;">​</a></h2><p>OrangeFox 是基于 TWRP 的增强版，界面更美观，功能更多。</p><ol><li>下载 <a href="https://orangefox.download/" target="_blank" rel="noreferrer">OrangeFox Recovery</a></li><li>同样通过 Fastboot 刷入：</li></ol><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">fastboot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> flash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> recovery</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> OrangeFox.img</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="recovery-常用操作" tabindex="-1">Recovery 常用操作 <a class="header-anchor" href="#recovery-常用操作" aria-label="Permalink to &quot;Recovery 常用操作&quot;">​</a></h2><h3 id="备份系统" tabindex="-1">备份系统 <a class="header-anchor" href="#备份系统" aria-label="Permalink to &quot;备份系统&quot;">​</a></h3><ol><li>进入 Recovery → Backup</li><li>勾选需要备份的分区：Boot、System、Data、Vendor</li><li>选择存储位置（建议外置 SD 卡或 OTG U盘）</li><li>滑动确认备份</li></ol><h3 id="恢复系统" tabindex="-1">恢复系统 <a class="header-anchor" href="#恢复系统" aria-label="Permalink to &quot;恢复系统&quot;">​</a></h3><ol><li>Recovery → Restore</li><li>选择之前的备份包</li><li>滑动确认恢复</li></ol><h3 id="刷入-rom" tabindex="-1">刷入 ROM <a class="header-anchor" href="#刷入-rom" aria-label="Permalink to &quot;刷入 ROM&quot;">​</a></h3><ol><li>Recovery → Wipe → 滑动恢复出厂设置</li><li>Recovery → Install → 选择 ROM 包</li><li>滑动确认刷入</li><li>重启系统</li></ol><div class="danger custom-block"><p class="custom-block-title">警告</p><p>刷机前务必做好完整备份！跨大版本刷机建议格式化 Data 分区。</p></div>`,20)])])}const b=e(r,[["render",o]]);export{k as __pageData,b as default};
